const updateAgent = `-- name: UpdateAgent :one
UPDATE agent SET
    name = COALESCE($2, name),
    description = COALESCE($3, description),
    avatar_url = COALESCE($4, avatar_url),
    runtime_config = COALESCE($5, runtime_config),
    runtime_mode = COALESCE($6, runtime_mode),
    runtime_id = COALESCE($7, runtime_id),
    visibility = COALESCE($8, visibility),
    status = COALESCE($9, status),
    max_concurrent_tasks = COALESCE($10, max_concurrent_tasks),
    instructions = COALESCE($11, instructions),
    custom_env = COALESCE($12, custom_env),
    updated_at = now()
WHERE id = $1
RETURNING id, workspace_id, name, avatar_url, runtime_mode, runtime_config, visibility, status, max_concurrent_tasks, owner_id, created_at, updated_at, description, runtime_id, instructions, archived_at, archived_by, custom_env
`

type UpdateAgentParams struct {
	ID                 pgtype.UUID `json:"id"`
	Name               pgtype.Text `json:"name"`
	Description        pgtype.Text `json:"description"`
	AvatarUrl          pgtype.Text `json:"avatar_url"`
	RuntimeConfig      []byte      `json:"runtime_config"`
	RuntimeMode        pgtype.Text `json:"runtime_mode"`
	RuntimeID          pgtype.UUID `json:"runtime_id"`
	Visibility         pgtype.Text `json:"visibility"`
	Status             pgtype.Text `json:"status"`
	MaxConcurrentTasks pgtype.Int4 `json:"max_concurrent_tasks"`
	Instructions       pgtype.Text `json:"instructions"`
	CustomEnv          []byte      `json:"custom_env"`
}

func (q *Queries) UpdateAgent(ctx context.Context, arg UpdateAgentParams) (Agent, error) {
	row := q.db.QueryRow(ctx, updateAgent,
		arg.ID,
		arg.Name,
		arg.Description,
		arg.AvatarUrl,
		arg.RuntimeConfig,
		arg.RuntimeMode,
		arg.RuntimeID,
		arg.Visibility,
		arg.Status,
		arg.MaxConcurrentTasks,
		arg.Instructions,
		arg.CustomEnv,
	)
	var i Agent
	err := row.Scan(
		&i.ID,
		&i.WorkspaceID,
		&i.Name,
		&i.AvatarUrl,
		&i.RuntimeMode,
		&i.RuntimeConfig,
		&i.Visibility,
		&i.Status,
		&i.MaxConcurrentTasks,
		&i.OwnerID,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.Description,
		&i.RuntimeID,
		&i.Instructions,
		&i.ArchivedAt,
		&i.ArchivedBy,
		&i.CustomEnv,
	)
	return i, err
}

